// Admin pastel — upload múltiplo de imagens por opção, código automático por opção.

const STORAGE_KEY_P = "crisborba_temas_v2";
const ADMIN_SESSION_P = "crisborba_admin_session";
const API = "api";
const LOGO_WM_URL = 'data:image/jpeg;base64,';

function loadTemasPastel() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY_P);
    if (raw) return JSON.parse(raw);
  } catch (e) {}
  return null;
}
async function saveTemasPastel(temas) {
  try { localStorage.setItem(STORAGE_KEY_P, JSON.stringify(temas)); } catch (e) {}
  try {
    for (const tema of temas) {
      await fetch(API + '/temas.php', {
        method: 'POST', credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(tema)
      });
    }
  } catch (e) { console.warn('Erro ao salvar temas:', e); }
}
function resetTemasPastel() {
  try { localStorage.removeItem(STORAGE_KEY_P); } catch (e) {}
}
async function loadTemasRemote() {
  try {
    const res = await fetch(API + '/temas.php?t=' + Date.now());
    if (!res.ok) return null;
    const data = await res.json();
    if (Array.isArray(data)) {
      try { localStorage.setItem(STORAGE_KEY_P, JSON.stringify(data)); } catch (e) {}
      return data;
    }
  } catch (e) {}
  return null;
}

function gerarCodigo(nomeTema, indiceOpcao, offsetGlobal = 0) {
  const num = String((offsetGlobal || 0) + indiceOpcao + 1).padStart(3, "0");
  return `CRIS-${num}`;
}

// Retorna o maior número de código já usado em todos os temas
function maxCodigoExistente(temas) {
  let max = 0;
  temas.forEach(t => t.opcoes.forEach(o => {
    if (o.codigo) {
      const n = parseInt(o.codigo.replace('CRIS-', ''), 10);
      if (!isNaN(n) && n > max) max = n;
    }
  }));
  return max;
}

async function aplicarMarcaDagua(file) {
  return new Promise((resolve) => {
    const fotoUrl = URL.createObjectURL(file);
    const fotoImg = new Image();
    const logoImg = new Image();

    fotoImg.onload = () => {
      logoImg.onload = () => {
        try {
          const W = fotoImg.naturalWidth;
          const H = fotoImg.naturalHeight;

          // Canvas principal com a foto
          const canvas = document.createElement('canvas');
          canvas.width = W;
          canvas.height = H;
          const ctx = canvas.getContext('2d');
          ctx.drawImage(fotoImg, 0, 0);

          // Logo: 22% da largura da foto, canto inferior direito
          const logoW = Math.round(W * 0.22);
          const logoH = Math.round(logoW * logoImg.naturalHeight / logoImg.naturalWidth);
          const margin = Math.round(W * 0.025);

          // Offscreen canvas: remove fundo branco do logo JPEG
          const off = document.createElement('canvas');
          off.width = logoW;
          off.height = logoH;
          const offCtx = off.getContext('2d');
          offCtx.drawImage(logoImg, 0, 0, logoW, logoH);
          const imgData = offCtx.getImageData(0, 0, logoW, logoH);
          const d = imgData.data;
          for (let i = 0; i < d.length; i += 4) {
            const lum = d[i] * 0.299 + d[i + 1] * 0.587 + d[i + 2] * 0.114;
            if (lum > 230) d[i + 3] = 0;
            else if (lum > 185) d[i + 3] = Math.round((230 - lum) / 45 * 255);
          }
          offCtx.putImageData(imgData, 0, 0);

          // Aplica logo semi-transparente sobre a foto
          ctx.globalAlpha = 0.45;
          ctx.drawImage(off, W - logoW - margin, H - logoH - margin);
          ctx.globalAlpha = 1;

          canvas.toBlob(
            (blob) => {
              URL.revokeObjectURL(fotoUrl);
              resolve(blob ? new File([blob], file.name, { type: 'image/jpeg' }) : file);
            },
            'image/jpeg', 0.92
          );
        } catch (e) {
          console.warn('Marca d\'água falhou, subindo sem marca:', e);
          URL.revokeObjectURL(fotoUrl);
          resolve(file);
        }
      };
      // Se o logo falhar, sobe a foto sem marca d'água
      logoImg.onerror = () => { URL.revokeObjectURL(fotoUrl); resolve(file); };
      logoImg.src = LOGO_WM_URL;
    };
    fotoImg.onerror = () => { URL.revokeObjectURL(fotoUrl); resolve(file); };
    fotoImg.src = fotoUrl;
  });
}

async function uploadImagemSupabase(file) {
  const fd = new FormData();
  fd.append('foto', file);
  const res = await fetch(API + '/upload.php', { method: 'POST', credentials: 'include', body: fd });
  if (!res.ok) throw new Error('Falha no upload');
  const json = await res.json();
  if (json.error) throw new Error(json.error);
  return json.url;
}

// Normaliza imagens de uma opção (compatível com schema antigo imagem:string)
function normalizarImagens(o) {
  if (o.imagens && o.imagens.length > 0) return o.imagens;
  if (o.imagem) return [o.imagem];
  return [];
}

function AdminPanelPastel({ onClose, temas, setTemas }) {
  const [logged, setLogged] = React.useState(false);
  const [email, setEmail] = React.useState("");
  const [pass, setPass] = React.useState("");
  const [erro, setErro] = React.useState("");
  const [loading, setLoading] = React.useState(false);

  React.useEffect(() => {
    fetch(API + '/auth.php?action=check', { credentials: 'include' })
      .then(r => r.json()).then(d => { if (d.logged) setLogged(true); }).catch(() => {});
  }, []);
  const [view, setView] = React.useState("list");
  const [editId, setEditId] = React.useState(null);

  const formVazio = { nome: "", categoria: "Aniversário Infantil", tipo: "", tags: "", descricao: "", opcoes: [{ titulo: "", legenda: "", imagens: [] }] };
  const [form, setForm] = React.useState(formVazio);
  const [tipoErro, setTipoErro] = React.useState(false);

  async function tryLogin(e) {
    e.preventDefault();
    setLoading(true); setErro("");
    try {
      const res = await fetch(API + '/auth.php', {
        method: 'POST', credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'login', email, senha: pass })
      });
      const data = await res.json();
      if (data.ok) { setLogged(true); }
      else { setErro(data.error || 'E-mail ou senha incorretos.'); }
    } catch { setErro('Erro de conexão. Tente novamente.'); }
    setLoading(false);
  }
  async function logout() {
    await fetch(API + '/auth.php', {
      method: 'POST', credentials: 'include',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ action: 'logout' })
    }).catch(() => {});
    setLogged(false); setEmail(''); setPass('');
  }

  function addOpcao() {
    setForm({ ...form, opcoes: [...form.opcoes, { titulo: "", legenda: "", imagens: [] }] });
  }
  function rmOpcao(i) {
    if (form.opcoes.length === 1) return;
    setForm({ ...form, opcoes: form.opcoes.filter((_, idx) => idx !== i) });
  }
  function setOpcaoField(i, key, val) {
    const next = [...form.opcoes];
    next[i] = { ...next[i], [key]: val };
    setForm({ ...form, opcoes: next });
  }

  async function uploadOpcaoImagem(opcaoI, file) {
    if (!file) return;
    // Adiciona placeholder "enviando"
    setForm(prev => {
      const opcoes = prev.opcoes.map((o, idx) =>
        idx === opcaoI ? { ...o, imagens: [...(o.imagens || []), '__enviando__'] } : o
      );
      return { ...prev, opcoes };
    });
    try {
      const fileComMarca = await aplicarMarcaDagua(file);
      const url = await uploadImagemSupabase(fileComMarca);
      setForm(prev => {
        const opcoes = prev.opcoes.map((o, idx) => {
          if (idx !== opcaoI) return o;
          const imgs = [...(o.imagens || [])];
          const pos = imgs.lastIndexOf('__enviando__');
          if (pos >= 0) imgs[pos] = url;
          return { ...o, imagens: imgs };
        });
        return { ...prev, opcoes };
      });
    } catch (e) {
      setForm(prev => {
        const opcoes = prev.opcoes.map((o, idx) => {
          if (idx !== opcaoI) return o;
          return { ...o, imagens: (o.imagens || []).filter(img => img !== '__enviando__') };
        });
        return { ...prev, opcoes };
      });
      alert("Erro ao fazer upload: " + e.message);
    }
  }

  function removeImagem(opcaoI, imgI) {
    setForm(prev => {
      const opcoes = prev.opcoes.map((o, idx) => {
        if (idx !== opcaoI) return o;
        const imgs = [...(o.imagens || [])];
        imgs.splice(imgI, 1);
        return { ...o, imagens: imgs };
      });
      return { ...prev, opcoes };
    });
  }

  function salvarTema(e) {
    e.preventDefault();
    if (!form.nome.trim()) return alert("Nome obrigatório");
    if (!form.tipo) { setTipoErro(true); return; }
    setTipoErro(false);
    const nomeTrim = form.nome.trim();
    let next;

    if (editId) {
      let prox = maxCodigoExistente(temas);
      const codigosUsados = new Set();
      const atualizado = {
        ...temas.find(t => t.id === editId),
        nome: nomeTrim, categoria: form.categoria, tipo: form.tipo || "parceria",
        tags: form.tags.split(",").map(t => t.trim().toLowerCase()).filter(Boolean),
        descricao: form.descricao.trim() || "Tema personalizado adicionado pela Cris.",
        opcoes: form.opcoes.map((o) => {
          const imagens = (o.imagens || []).filter(img => img && img !== '__enviando__');
          // Mantém código existente apenas se não for duplicado dentro do mesmo tema
          if (o.codigo && !codigosUsados.has(o.codigo)) {
            codigosUsados.add(o.codigo);
            return { titulo: o.titulo.trim() || "Versão única", legenda: o.legenda.trim() || "", imagens, codigo: o.codigo };
          }
          prox += 1;
          const c = `CRIS-${String(prox).padStart(3, "0")}`;
          codigosUsados.add(c);
          return { titulo: o.titulo.trim() || "Versão única", legenda: o.legenda.trim() || "", imagens, codigo: c };
        }),
      };
      next = temas.map(t => t.id === editId ? atualizado : t).sort((a, b) => a.nome.localeCompare(b.nome, "pt-BR"));
    } else {
      let prox = maxCodigoExistente(temas);
      const novo = {
        id: nomeTrim.toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g, "")
              .replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "") + "-" + Date.now().toString(36),
        nome: nomeTrim, categoria: form.categoria, tipo: form.tipo || "parceria",
        tags: form.tags.split(",").map(t => t.trim().toLowerCase()).filter(Boolean),
        descricao: form.descricao.trim() || "Tema personalizado adicionado pela Cris.",
        opcoes: form.opcoes.map((o) => {
          prox += 1;
          const imagens = (o.imagens || []).filter(img => img && img !== '__enviando__');
          return { titulo: o.titulo.trim() || "Versão única", legenda: o.legenda.trim() || "", imagens, codigo: `CRIS-${String(prox).padStart(3, "0")}` };
        }),
      };
      next = [...temas, novo].sort((a, b) => a.nome.localeCompare(b.nome, "pt-BR"));
    }

    setTemas(next);
    saveTemasPastel(next);
    setForm(formVazio);
    setEditId(null);
    setTipoErro(false);
    setView("list");
  }

  function editarTema(tema) {
    setForm({
      nome: tema.nome, categoria: tema.categoria, tipo: tema.tipo || "parceria",
      tags: (tema.tags || []).join(", "), descricao: tema.descricao || "",
      opcoes: tema.opcoes.map(o => ({
        titulo: o.titulo, legenda: o.legenda || "",
        imagens: normalizarImagens(o),
        codigo: o.codigo
      })),
    });
    setEditId(tema.id);
    setView("add");
  }

  function removerTema(id) {
    if (!confirm("Remover este tema?")) return;
    const next = temas.filter(t => t.id !== id);
    setTemas(next); saveTemasPastel(next);
  }

  function resetar() {
    if (!confirm("Voltar para a lista padrão de temas? Suas adições serão perdidas.")) return;
    resetTemasPastel();
    const defaultTemas = window.getTemasComCodigo ? window.getTemasComCodigo() : [];
    setTemas(defaultTemas);
    saveTemasPastel(defaultTemas);
  }

  const categoriasOpts = ["Adulto & 15 anos", "Aniversário Infantil", "Batizado", "Casamento", "Chá de bebê", "Datas especiais"];

  return (
    <div className="admin-backdrop" onClick={onClose}>
      <div className="admin-panel" onClick={(e) => e.stopPropagation()}>
        <header className="admin-head">
          <div>
            <span className="admin-eyebrow">Cris Borba Decorações</span>
            <h2>Área da Cris</h2>
          </div>
          <button className="admin-close" onClick={onClose}>fechar ✕</button>
        </header>

        {!logged ? (
          <form className="admin-login" onSubmit={tryLogin}>
            <p>Acesso restrito ao administrador.</p>
            <label>
              <span>E-mail</span>
              <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} autoFocus required />
            </label>
            <label>
              <span>Senha</span>
              <input type="password" value={pass} onChange={(e) => setPass(e.target.value)} required />
            </label>
            {erro && <p className="admin-erro">{erro}</p>}
            <button type="submit" className="btn btn-primary" disabled={loading}>{loading ? "Verificando..." : "Entrar →"}</button>
          </form>
        ) : (
          <div className="admin-body">
            <nav className="admin-nav">
              <button className={view === "list" ? "active" : ""} onClick={() => { setView("list"); setEditId(null); setForm(formVazio); setTipoErro(false); }}>
                Temas ({temas.length})
              </button>
              <button className={view === "add" ? "active" : ""} onClick={() => { setEditId(null); setForm(formVazio); setTipoErro(false); setView("add"); }}>
                {view === "add" && editId ? "Editando tema" : "+ Adicionar tema"}
              </button>
              <div className="admin-nav-spacer" />
              <button className="admin-nav-side" onClick={resetar}>resetar</button>
              <button className="admin-nav-side" onClick={logout}>sair</button>
            </nav>

            {view === "list" && (
              <div className="admin-list">
                {temas.map((t, i) => (
                  <div key={t.id} className="admin-row">
                    <span className="admin-row-num">{String(i + 1).padStart(2, "0")}</span>
                    <div className="admin-row-thumb">
                      <window.PlaceholderImg paleta={t.opcoes[0].paleta || "Pastel Misto"} imagem={normalizarImagens(t.opcoes[0])[0] || null} label="" />
                    </div>
                    <div className="admin-row-info">
                      <strong>{t.nome} <span className="admin-tipo-badge" data-tipo={t.tipo || "parceria"}>{(t.tipo || "parceria") === "particular" ? "Particular" : "Parceria"}</span></strong>
                      <span>{t.categoria} · {t.opcoes.length} opç{t.opcoes.length > 1 ? "ões" : "ão"} · códigos: {t.opcoes.map(o => o.codigo).join(", ")}</span>
                    </div>
                    <button className="admin-row-edit" onClick={() => editarTema(t)}>editar</button>
                    <button className="admin-row-rm" onClick={() => removerTema(t.id)}>remover</button>
                  </div>
                ))}
              </div>
            )}

            {view === "add" && (
              <form className="admin-form" onSubmit={salvarTema}>
                <div className="admin-form-row">
                  <label>
                    <span>Nome do tema *</span>
                    <input type="text" value={form.nome} onChange={(e) => setForm({...form, nome: e.target.value})} placeholder="ex: Unicórnios" />
                  </label>
                  <label>
                    <span>Categoria</span>
                    <select value={form.categoria} onChange={(e) => setForm({...form, categoria: e.target.value})}>
                      {categoriasOpts.map(c => <option key={c}>{c}</option>)}
                    </select>
                  </label>
                </div>

                <div className="admin-tipo-section">
                  <div className="admin-tipo-label">Tipo de decoração <span className="admin-tipo-req">*</span></div>
                  <div className="admin-tipo-radios">
                    <label className={`admin-tipo-radio admin-tipo-parceria${form.tipo === "parceria" ? " selected" : ""}`}>
                      <input type="radio" name="admin-tipo" value="parceria"
                        checked={form.tipo === "parceria"}
                        onChange={() => { setForm({...form, tipo: "parceria"}); setTipoErro(false); }} />
                      <div className="admin-tipo-radio-check" />
                      <div className="admin-tipo-radio-body">
                        <strong>Parceria com buffet</strong>
                        <span>Aparece no portfólio principal do site</span>
                      </div>
                    </label>
                    <label className={`admin-tipo-radio admin-tipo-particular${form.tipo === "particular" ? " selected" : ""}`}>
                      <input type="radio" name="admin-tipo" value="particular"
                        checked={form.tipo === "particular"}
                        onChange={() => { setForm({...form, tipo: "particular"}); setTipoErro(false); }} />
                      <div className="admin-tipo-radio-check" />
                      <div className="admin-tipo-radio-body">
                        <strong>Particular</strong>
                        <span>Aparece em "Decorações particulares"</span>
                      </div>
                    </label>
                  </div>
                  {tipoErro && (
                    <div className="admin-tipo-erro">
                      <span>⚠</span> Selecione o tipo antes de salvar — esta escolha define onde a decoração aparece no site.
                    </div>
                  )}
                </div>

                <label>
                  <span>Palavras-chave (separadas por vírgula)</span>
                  <input type="text" value={form.tags} onChange={(e) => setForm({...form, tags: e.target.value})} placeholder="menina, fantasia, colorido, 1 ano" />
                </label>

                <label>
                  <span>Descrição</span>
                  <textarea rows="3" value={form.descricao} onChange={(e) => setForm({...form, descricao: e.target.value})} placeholder="Conte sobre o tema, atmosfera, elementos…" />
                </label>

                <div className="admin-opcoes">
                  <div className="admin-opcoes-head">
                    <span>Opções/versões · cada uma tem código automático e várias fotos</span>
                    <button type="button" onClick={addOpcao}>+ adicionar opção</button>
                  </div>
                  {form.opcoes.map((o, i) => {
                    const baseCount = temas.reduce((acc, t) => t.id === editId ? acc : acc + t.opcoes.length, 0);
                    const codigoLabel = o.codigo ? o.codigo : `CRIS-${String(baseCount + i + 1).padStart(3, "0")} (novo)`;
                    return (
                      <div key={i} className="admin-opcao admin-opcao-pastel">
                        <div className="admin-opcao-pastel-top">
                          <span className="admin-opcao-num">{String(i + 1).padStart(2, "0")}</span>
                          <span className="admin-opcao-cod">código: <strong>{codigoLabel}</strong></span>
                          <button type="button" className="admin-opcao-rm" onClick={() => rmOpcao(i)}>remover</button>
                        </div>

                        <div className="admin-opcao-fields-pastel" style={{marginBottom: 12}}>
                          <input
                            type="text"
                            placeholder="Título da versão (ex: Versão Mesa Hulk)"
                            value={o.titulo}
                            onChange={(e) => setOpcaoField(i, "titulo", e.target.value)}
                          />
                          <input
                            type="text"
                            placeholder="Legenda curta"
                            value={o.legenda}
                            onChange={(e) => setOpcaoField(i, "legenda", e.target.value)}
                          />
                        </div>

                        <div className="admin-imgs-label">Fotos desta opção</div>
                        <div className="admin-imgs-grid">
                          {(o.imagens || []).map((img, imgI) =>
                            img === '__enviando__' ? (
                              <div key={imgI} className="admin-img-thumb admin-img-enviando">
                                <span>⏳</span>
                              </div>
                            ) : (
                              <div key={imgI} className="admin-img-thumb">
                                <img src={img} alt={`foto ${imgI + 1}`} />
                                <button type="button" className="admin-img-rm" onClick={() => removeImagem(i, imgI)}>✕</button>
                              </div>
                            )
                          )}
                          <label className="admin-img-add">
                            <input type="file" accept="image/*"
                              onChange={(e) => { if (e.target.files[0]) uploadOpcaoImagem(i, e.target.files[0]); e.target.value = ''; }} />
                            <span className="up-icon">⤴</span>
                            <span>+ foto</span>
                          </label>
                        </div>
                      </div>
                    );
                  })}
                </div>

                <div className="admin-form-foot">
                  <button type="button" className="btn btn-ghost" onClick={() => { setForm(formVazio); setEditId(null); setTipoErro(false); setView("list"); }}>cancelar</button>
                  <button type="submit" className="btn btn-primary">{editId ? "Salvar alterações →" : "Salvar tema →"}</button>
                </div>
              </form>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

window.AdminPanel = AdminPanelPastel;
window.loadTemas = loadTemasPastel;
window.saveTemas = saveTemasPastel;
window.loadTemasRemote = loadTemasRemote;
window.gerarCodigo = gerarCodigo;



